arguments.file_text:
namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings == 0 ? 0 : (double)RatingSum / TotalRatings;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious pizza with fresh mozzarella, tomatoes, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F (245°C).", "Roll out dough on a floured surface.", "Spread crushed tomatoes over the dough.", "Tear mozzarella and distribute evenly.", "Bake for 10–12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 50
            },
            new Recipe
            {
                Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a creamy, spiced tomato sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Cumin", "Turmeric"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger in a pan.", "Add tomato sauce and spices, simmer 15 minutes.", "Stir in cream and add chicken pieces.", "Simmer 10 more minutes and serve with rice."],
                TotalRatings = 8, RatingSum = 35
            },
            new Recipe
            {
                Id = 3, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "A Roman classic with eggs, cheese, pancetta, and black pepper.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper", "Salt"],
                Steps = ["Cook spaghetti in salted boiling water until al dente.", "Crisp pancetta in a skillet over medium heat.", "Whisk eggs and grated Pecorino together.", "Drain pasta, reserving some cooking water.", "Toss hot pasta with pancetta, then remove from heat.", "Stir in egg mixture quickly, adding pasta water to create a creamy sauce."],
                TotalRatings = 15, RatingSum = 68
            },
            new Recipe
            {
                Id = 4, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = ["Brown ground beef in a skillet over medium-high heat.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry skillet or microwave.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, sour cream, and salsa."],
                TotalRatings = 10, RatingSum = 42
            },
            new Recipe
            {
                Id = 5, Title = "Pad Thai", Category = "Thai",
                Description = "Stir-fried rice noodles with shrimp, peanuts, and tamarind sauce.",
                Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Green onions", "Peanuts", "Tamarind paste", "Fish sauce", "Sugar", "Lime"],
                Steps = ["Soak rice noodles in warm water for 30 minutes, then drain.", "Mix tamarind paste, fish sauce, and sugar for the sauce.", "Stir-fry shrimp until pink, then push to the side.", "Scramble eggs in the same pan.", "Add noodles and sauce, toss to combine.", "Top with bean sprouts, peanuts, green onions, and a squeeze of lime."],
                TotalRatings = 6, RatingSum = 27
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh avocado dip with lime, cilantro, and jalapeño.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps = ["Halve and pit the avocados, scoop into a bowl.", "Mash to desired consistency.", "Stir in diced onion, jalapeño, tomato, and cilantro.", "Add lime juice and salt to taste.", "Serve immediately with tortilla chips."],
                TotalRatings = 20, RatingSum = 88
            },
            new Recipe
            {
                Id = 7, Title = "Miso Soup", Category = "Japanese",
                Description = "A light and warming Japanese soup with tofu and seaweed.",
                Ingredients = ["Dashi stock", "Miso paste", "Silken tofu", "Wakame seaweed", "Green onions"],
                Steps = ["Bring dashi stock to a simmer.", "Dissolve miso paste in a small amount of warm dashi.", "Add tofu cubes and wakame to the pot.", "Stir in the miso mixture — do not boil.", "Serve garnished with sliced green onions."],
                TotalRatings = 5, RatingSum = 21
            },
            new Recipe
            {
                Id = 8, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Description = "Chewy, buttery cookies loaded with chocolate chips.",
                Ingredients = ["Butter", "Brown sugar", "White sugar", "Eggs", "Vanilla extract", "All-purpose flour", "Baking soda", "Salt", "Chocolate chips"],
                Steps = ["Preheat oven to 375°F (190°C).", "Cream butter and sugars until fluffy.", "Beat in eggs and vanilla.", "Mix in flour, baking soda, and salt.", "Fold in chocolate chips.", "Drop rounded tablespoons onto baking sheets.", "Bake 9–11 minutes until golden edges."],
                TotalRatings = 25, RatingSum = 118
            },
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(string title, string category, string description, List<string> ingredients, List<string> steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Description = description,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
