@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>RecipeShare — Home</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 Welcome to RecipeShare</h1>
    <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<h2 class="mb-3">Browse by Category</h2>
<div class="row row-cols-1 row-cols-sm-2 row-cols-md-3 g-4">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col">
