                </div>
            </div>
        </div>
    }
</div>

<div class="text-center mt-5">
    <h4>Have a recipe to share?</h4>
    <a href="submit" class="btn btn-success btn-lg mt-2">📝 Submit a Recipe</a>
</div>

@code {
    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Thai" => "🍜",
        "Japanese" => "🍣",
        "Desserts" => "🍪",
        _ => "🍽️"
    };
}

arguments.file_text:
@page "/categories"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>All Categories — RecipeShare</PageTitle>

<h1>Recipe Categories</h1>
<p>Select a category to browse recipes.</p>

<div class="list-group">
    @foreach (var category in RecipeService.GetCategories())
    {
        <a href="@($"category/{category}")" class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
            @category
            <span class="badge bg-primary rounded-pill">@RecipeService.GetByCategory(category).Count</span>
        </a>
    }
</div>

@page "/category/{CategoryName}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item"><a href="/categories">Categories</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var recipe in Recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            <span class="text-warning">@RenderStars(recipe.AverageRating)</span>
                            <small class="text-muted">(@recipe.TotalRatings ratings)</small>
                        </div>
                        <a href="@($"recipe/{recipe.Id}")" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/recipe/{RecipeId:int}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/categories">Categories</a></li>
            <li class="breadcrumb-item"><a href="@($"/category/{Recipe.Category}")">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p class="lead">@Recipe.Description</p>

    <div class="mb-4">
        <span class="text-warning fs-5">@(new string('★', (int)Math.Round(Recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(Recipe.AverageRating)))</span>
        <span class="text-muted">(@Recipe.AverageRating.ToString("F1") avg — @Recipe.TotalRatings ratings)</span>
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <h3>Steps</h3>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in Recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="card mt-3">
        <div class="card-body">
            <h4 class="card-title">Rate this recipe</h4>
            <StarRating RecipeId="Recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(RecipeId);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        int star = i;
        <span
            class="fs-3"
            style="cursor: pointer; color: @(star <= (HoverStar ?? SelectedStar) ? "#ffc107" : "#dee2e6");"
            @onclick="() => SelectStar(star)"
            @onmouseover="() => HoverStar = star"
            @onmouseout="() => HoverStar = null">
            ★
        </span>
    }
</div>

@if (Submitted)
{
    <div class="alert alert-success mt-2 py-1 px-2 d-inline-block">
        Thanks! You rated this @SelectedStar star@(SelectedStar != 1 ? "s" : "").
    </div>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int SelectedStar { get; set; }
    private int? HoverStar { get; set; }
    private bool Submitted { get; set; }

    private void SelectStar(int star)
    {
        SelectedStar = star;
        Submitted = true;
        RecipeService.AddRating(RecipeId, star);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (!string.IsNullOrEmpty(SuccessMessage))
{
    <div class="alert alert-success">@SuccessMessage</div>
}

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => Model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputText id="category" class="form-control" @bind-Value="Model.Category" placeholder="e.g., Desserts, Italian, Mexican" />
        <ValidationMessage For="() => Model.Category" />
    </div>

    <div class="mb-3">
        <label for="description" class="form-label">Short Description</label>
        <InputTextArea id="description" class="form-control" @bind-Value="Model.Description" rows="2" placeholder="A brief description of your recipe" />
        <ValidationMessage For="() => Model.Description" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" @bind-Value="Model.IngredientsText" rows="5" placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
        <ValidationMessage For="() => Model.IngredientsText" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" @bind-Value="Model.StepsText" rows="5" placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Combine wet and dry ingredients." />
        <ValidationMessage For="() => Model.StepsText" />
    </div>

    <button type="submit" class="btn btn-success btn-lg">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel Model { get; set; } = new();
    private string? SuccessMessage { get; set; }

    private void HandleSubmit()
    {
        var ingredients = Model.IngredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        var steps = Model.StepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        var recipe = RecipeService.AddRecipe(
            Model.Title,
            Model.Category,
            Model.Description,
            ingredients,
            steps);

        SuccessMessage = $"'{recipe.Title}' was submitted successfully! View it in the {recipe.Category} category.";
        Model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Description is required.")]
        public string Description { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "At least one ingredient is required.")]
        public string IngredientsText { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "At least one step is required.")]
        public string StepsText { get; set; } = string.Empty;
    }
}

